  ('fire-eq-eng-moex-01133', 'fire-eq-eng', 'fire-eq-eng-moex-097-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依防火牆及防火水幕設置基準規定，防火水幕設備之水源應連結加壓送水裝置，加壓送水裝置啟動後幾分 鐘內應能形成水幕？', '["3分鐘內", "6分鐘內", "9分鐘內", "12分鐘內"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "d2e9dde1663a", "answer_pdf_sha1": "3cb24e4147ff", "source_family": "moex-gov-tw", "moex": {"exam_code": "097250", "c": "901", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "097", "exam_name": "097年專技建築師、技師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 27, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-01134', 'fire-eq-eng', 'fire-eq-eng-moex-097-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依防火牆及防火水幕設置基準規定，防火水幕之防護高度在10公尺以下時，其每公尺水幕長度放水量應在 每分鐘多少公升以上？', '["20公升", "50公升", "100公升", "200公升"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "d2e9dde1663a", "answer_pdf_sha1": "3cb24e4147ff", "source_family": "moex-gov-tw", "moex": {"exam_code": "097250", "c": "901", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "097", "exam_name": "097年專技建築師、技師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 28, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-01135', 'fire-eq-eng', 'fire-eq-eng-moex-097-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依防焰性能認證實施要點規定，防焰性能試驗之產品試樣規格，下列敘述何者錯誤？', '["窗簾、布幕，須經水洗及乾洗處理者：2平方公尺以上", "地毯等地坪舖設物：1平方公尺以上", "施工用帆布：2平方公尺以上", "室內展示用廣告合板：1.6平方公尺以上"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "d2e9dde1663a", "answer_pdf_sha1": "3cb24e4147ff", "source_family": "moex-gov-tw", "moex": {"exam_code": "097250", "c": "901", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "097", "exam_name": "097年專技建築師、技師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 29, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-01136', 'fire-eq-eng', 'fire-eq-eng-moex-097-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依「消防設備師及消防設備士管理辦法」之規定，下列敘述何者正確？', '["講習所需經費由受訓人員自行負擔，其金額由講習單位報請縣市政府核定後實施", "直轄市、縣（市）之消防設備師或消防設備士達20人以上者，得組織直轄市、縣（市）消防設備師公會 或消防設備士公會", "消防設備師及消防設備士，自取得證書日起每2年應接受講習一次", "消防設備師及消防設備士因重病或重大事故無法接受前項講習時，得檢具證明文件向中央主管機關申請 核准延期"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "d2e9dde1663a", "answer_pdf_sha1": "3cb24e4147ff", "source_family": "moex-gov-tw", "moex": {"exam_code": "097250", "c": "901", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "097", "exam_name": "097年專技建築師、技師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 30, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-01137', 'fire-eq-eng', 'fire-eq-eng-moex-097-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依各類場所消防安全設備設置標準之規定，下列何者其消防安全設備之設置適用變更用途後之標準？', '["Ｋ書中心變更為補習班", "老人文康機構變更為護理之家機構", "中度危險工作場所變更為高度危險工作場所", "幼稚園變更為社區復健中心"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "d2e9dde1663a", "answer_pdf_sha1": "3cb24e4147ff", "source_family": "moex-gov-tw", "moex": {"exam_code": "097250", "c": "901", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "097", "exam_name": "097年專技建築師、技師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 31, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-01138', 'fire-eq-eng', 'fire-eq-eng-moex-097-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '未僱用領有合格證照者從事熱水器及配管之安裝，依消防法之規定可處罰鍰新台幣：', '["1千元以上，6千元以下", "6千元以上，3萬元以下", "1萬元以上，5萬元以下", "2萬元以上，10萬元以下"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "d2e9dde1663a", "answer_pdf_sha1": "3cb24e4147ff", "source_family": "moex-gov-tw", "moex": {"exam_code": "097250", "c": "901", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "097", "exam_name": "097年專技建築師、技師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 32, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-01139', 'fire-eq-eng', 'fire-eq-eng-moex-097-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依消防法之規定，應設消防安全設備之場所，其消防安全設備定期之檢查，下列敘述何者錯誤？', '["集合住宅：得由直轄市、縣（市）消防機關聘用或委託消防專業人員辦理，經費得由中央主管機關補助", "其管理權人應委託消防設備師或消防設備士，定期檢修消防安全設備", "集合住宅：得由直轄市、縣（市）消防機關聘用或委託消防專業人員辦理，經費由地方主管機關編列預 算支付", "高層建築物或地下建築物消防安全設備之定期檢修，其管理權人應委託地方主管機關審查合格之專業機 構辦理"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "d2e9dde1663a", "answer_pdf_sha1": "3cb24e4147ff", "source_family": "moex-gov-tw", "moex": {"exam_code": "097250", "c": "901", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "097", "exam_name": "097年專技建築師、技師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 33, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-01140', 'fire-eq-eng', 'fire-eq-eng-moex-097-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依照消防法第 11條之規定，除地面樓層達11層以上建築物、地下建築物外，下列何種場所，其管理權人 應使用附有防焰標示之地毯、窗簾、布幕、展示用廣告板及其他指定之防焰物品？', '["2百平方公尺的茶藝館", "2百平方公尺的健身休閒中心", "2百平方公尺的美術館", "2百平方公尺的展覽場"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "d2e9dde1663a", "answer_pdf_sha1": "3cb24e4147ff", "source_family": "moex-gov-tw", "moex": {"exam_code": "097250", "c": "901", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "097", "exam_name": "097年專技建築師、技師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 34, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-01141', 'fire-eq-eng', 'fire-eq-eng-moex-097-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依公共危險物品及可燃性高壓氣體設置標準暨安全管理辦法規定，液化石油氣儲存場所供二家以上共同使 用者，每一販賣場所使用之儲存面積，不得少於多少平方公尺？', '["3平方公尺", "5平方公尺", "6平方公尺", "10平方公尺"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "d2e9dde1663a", "answer_pdf_sha1": "3cb24e4147ff", "source_family": "moex-gov-tw", "moex": {"exam_code": "097250", "c": "901", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "097", "exam_name": "097年專技建築師、技師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 35, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL),
  ('fire-eq-eng-moex-01142', 'fire-eq-eng', 'fire-eq-eng-moex-097-d69d8efd', 'sub-fire-eq-eng-01', NULL, 'single_choice', '依防焰性能試驗基準之規定，防焰物品「餘焰時間」應符合之規定，下列敘述何者正確？', '["地毯等地坪舖設物類不得超過30秒", "薄纖維製品（每平方公尺質量450公克以下者）不得超過3秒", "厚纖維製品（每平方公尺質量超過450公克者）不得超過15秒", "展示用廣告板不得超過15秒"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:19+00:00", "source_pdf_sha1": "d2e9dde1663a", "answer_pdf_sha1": "3cb24e4147ff", "source_family": "moex-gov-tw", "moex": {"exam_code": "097250", "c": "901", "s": "2001", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "消防法規", "year": "097", "exam_name": "097年專技建築師、技師、記帳士、第二次消防設備人員、不動產經紀人考試", "original_question_number": 36, "answer_corrected": false, "flags": ["answer_missing"], "slug": "fire-equipment-engineer", "db_exam_id": "fire-eq-eng"}'::jsonb, NULL)
